class Solution {
    public int maxSatisfied(int[] customers, int[] grumpy, int minutes) {
        int n = customers.length;
        int totalSatisfied = 0;
        int grumpyUnsatisfied = 0;
        int maxExtraSatisfied = 0;
        int left = 0;

        for (int right = 0; right < n; right++) {
            if (grumpy[right] == 1) {
                grumpyUnsatisfied += customers[right];
            } else {
                totalSatisfied += customers[right];
            }

            if (right - left + 1 > minutes) {
                if (grumpy[left] == 1) {
                    grumpyUnsatisfied -= customers[left];
                }
                left++;
            }

            maxExtraSatisfied = Math.max(maxExtraSatisfied, grumpyUnsatisfied);
        }

        return totalSatisfied + maxExtraSatisfied;
    }
}
